const a = [
  {"id":689,"text":"Mild hypochromic microcytic anemia is associated with which of the following pathologies?","explanation":null,"reference":"Sharma M, Pandey S, Ranjan R, Seth T, Saxena R. Prevalence of alpha thalassemia in microcytic anemia: a tertiary care experience from north india. Mediterranean Journal of Hematology and Infectious Diseases. Published January 1, 2015. Accessed June 7, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC4283920/","responses":[{"text":"Vitamin B12 deficiency","correct":false,"visible":false},{"text":"Beta-thalassemia major","correct":false,"visible":false},{"text":"Alpha-thalassemia minor","correct":true,"visible":false},{"text":"Diamond-Blackfan anemia","correct":false,"visible":false},{"text":"Hemoglobin H disease","correct":false,"visible":false}]},{"id":3571,"text":"Which of these act as an opsonin?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 78.","responses":[{"text":"C3a","correct":false,"visible":false},{"text":"C5a","correct":false,"visible":false},{"text":"Leukotriene B4","correct":false,"visible":false},{"text":"Cytokines","correct":false,"visible":false},{"text":"Fc portion of IgG","correct":true,"visible":false}]},{"id":3718,"text":"Which of the following cells are involved in the formation of epithelioid cells and giant cells in granulomatous inflammation?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Robbins SL, eds. Robbins Basic Pathology. 9th ed. Elsevier/Saunders; 2013: 97.","responses":[{"text":"Macrophages","correct":true,"visible":false},{"text":"B cells","correct":false,"visible":false},{"text":"Epithelial cells","correct":false,"visible":false},{"text":"T cells","correct":false,"visible":false},{"text":"Plasma cells","correct":false,"visible":false}]},{"id":3769,"text":"Which parasite causes blackwater fever and cerebral malaria?","explanation":null,"reference":"Rénia L, Wu Howland S, Claser C, et al. Cerebral malaria. Virulence. Published March 1, 2012. Accessed May 30, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC3396698/","responses":[{"text":"Plasmodium malariae","correct":false,"visible":false},{"text":"Plasmodium ovale","correct":false,"visible":false},{"text":"Plasmodium vivax","correct":false,"visible":false},{"text":"Plasmodium falciparum","correct":true,"visible":false},{"text":"Plasmodium knowlesi","correct":false,"visible":false}]},{"id":3770,"text":"Which system reaches the functional state first in the embryo?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 63.","responses":[{"text":"Respiratory","correct":false,"visible":false},{"text":"Skeletal","correct":false,"visible":false},{"text":"Excretory","correct":false,"visible":false},{"text":"Nervous","correct":false,"visible":false},{"text":"Cardiovascular","correct":true,"visible":false}]},{"id":3772,"text":"Where are white infarcts usually seen?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 286.","responses":[{"text":"Spleen","correct":true,"visible":false},{"text":"Testes","correct":false,"visible":false},{"text":"Ovaries","correct":false,"visible":false},{"text":"Lungs","correct":false,"visible":false},{"text":"Small intestine","correct":false,"visible":false}]},{"id":3774,"text":"Where does red infarct usually occur in?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Robbins SL, eds. Robbins Basic Pathology. 9th ed. Elsevier/Saunders; 2013: 131.","responses":[{"text":"Heart","correct":false,"visible":false},{"text":"Venous occlusion","correct":true,"visible":false},{"text":"Arterial occlusion","correct":false,"visible":false},{"text":"Spleen","correct":false,"visible":false},{"text":"Kidney","correct":false,"visible":false}]},{"id":3776,"text":"Which of the following is covered by pseudostratified columnar epithelium?","explanation":"The structure that is covered by **pseudostratified columnar epithelium** is the **pharyngeal tonsil**. Pseudostratified columnar epithelium is commonly found in the respiratory tract, including the lining of the pharynx (throat). The lingual tonsil, palatine tonsil, spleen, and lymph nodes do not have a lining of pseudostratified columnar epithelium.","reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 281.","responses":[{"text":"Spleen","correct":false,"visible":false},{"text":"Palatine tonsil","correct":false,"visible":false},{"text":"Pharyngeal tonsil","correct":true,"visible":false},{"text":"Lymph nodes","correct":false,"visible":false},{"text":"Lingual tonsil","correct":false,"visible":false}]},{"id":3781,"text":"Which one of the following is a plasma mediator?","explanation":null,"reference":"Markiewski MM, Lambris JD. The role of complement in inflammatory diseases from behind the scenes into the spotlight. The American Journal of Pathology. Published September 2007. Accessed May 30, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC1959484/","responses":[{"text":"Histamine and nitric oxide (NO)","correct":false,"visible":false},{"text":"Prostaglandins","correct":false,"visible":false},{"text":"Leukotrienes","correct":false,"visible":false},{"text":"Chemokines","correct":false,"visible":false},{"text":"Complement proteins","correct":true,"visible":false}]},{"id":3790,"text":"The breakdown of heme produces which of the following?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 303.","responses":[{"text":"Amino acids","correct":false,"visible":false},{"text":"Globulin","correct":false,"visible":false},{"text":"Glucose","correct":false,"visible":false},{"text":"Bile","correct":false,"visible":false},{"text":"Bilirubin","correct":true,"visible":false}]},{"id":3798,"text":"Heme is broken down in which of the following?","explanation":null,"reference":"Heme - an overview | sciencedirect topics. Accessed May 30, 2022. https://www.sciencedirect.com/topics/medicine-and-dentistry/heme","responses":[{"text":"Liver","correct":true,"visible":false},{"text":"Kidney","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Stomach","correct":false,"visible":false},{"text":"Bone marrow","correct":false,"visible":false}]},{"id":3799,"text":"Erythropoietin is mainly produced in which of the following?","explanation":null,"reference":"1) Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 414.\r\n\r\n2) Lacombe C, Da Silva JL, Bruneval P, et al. Erythropoietin: sites of synthesis and regulation of secretion. American Journal of Kidney Diseases: The Official Journal of the National Kidney Foundation. Published October 1991. https://pubmed.ncbi.nlm.nih.gov/1928074","responses":[{"text":"Spleen","correct":false,"visible":false},{"text":"Bone marrow","correct":false,"visible":false},{"text":"Liver","correct":false,"visible":false},{"text":"Kidney","correct":true,"visible":false},{"text":"Adrenal gland","correct":false,"visible":false}]},{"id":3829,"text":"Which drug is used for the reversal of heparin?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 278.","responses":[{"text":"Warfarin","correct":false,"visible":false},{"text":"Protamine sulfate","correct":true,"visible":false},{"text":"Bivalirudin","correct":false,"visible":false},{"text":"Enoxaparin","correct":false,"visible":false},{"text":"Vitamin K","correct":false,"visible":false}]},{"id":3830,"text":"Which of the following is considered normal bleeding time?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 460.","responses":[{"text":"30-50 seconds","correct":false,"visible":false},{"text":"15-20 minutes","correct":false,"visible":false},{"text":"6-20 minutes","correct":false,"visible":false},{"text":"2-5 minutes","correct":true,"visible":false},{"text":"5-10 minutes","correct":false,"visible":false}]},{"id":3831,"text":"Which of the following is true for hemophilia B?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Robbins SL, eds. Robbins Basic Pathology. 9th ed. Elsevier/Saunders; 2013: 663.","responses":[{"text":"Can be transmitted from father to daughter","correct":false,"visible":false},{"text":"Is characterized by a marked decrease in coagulation time","correct":false,"visible":false},{"text":"Also called Christmas disease","correct":true,"visible":false},{"text":"Can be treated by anticoagulants","correct":false,"visible":false},{"text":"Is an autosomal disorder","correct":false,"visible":false}]},{"id":3832,"text":"In which disease is the conjugated bilirubin not being transported outside the liver?","explanation":null,"reference":"Talaga ZJ, Vaidya PN. Dubin johnson syndrome. StatPearls. Published 2022. Accessed May 29, 2022. http://www.ncbi.nlm.nih.gov/books/NBK536994/","responses":[{"text":"Hemolytic anemia","correct":false,"visible":false},{"text":"Dubin Johnson syndrome","correct":true,"visible":false},{"text":"Gilberts syndrome","correct":false,"visible":false},{"text":"Criglar Najjar syndrome","correct":false,"visible":false},{"text":"Physiological Jaundice of the newborn","correct":false,"visible":false}]},{"id":3833,"text":"Which factor takes part in the intrinsic pathway?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 36.","responses":[{"text":"Heparin-like factor","correct":false,"visible":false},{"text":"Rheumatoid factor","correct":false,"visible":false},{"text":"Factor II","correct":false,"visible":false},{"text":"Hageman factor","correct":true,"visible":false},{"text":"Factor VII","correct":false,"visible":false}]},{"id":3834,"text":"Which of the following is a major plasma protein?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 833.","responses":[{"text":"Transferrin","correct":false,"visible":false},{"text":"Prothrombin","correct":false,"visible":false},{"text":"Haptoglobin","correct":false,"visible":false},{"text":"Albumin","correct":true,"visible":false},{"text":"Immunoglobulin","correct":false,"visible":false}]},{"id":3835,"text":"Which of the following characteristic is INCORRECT about basophils?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 244.","responses":[{"text":"Contain major basic proteins","correct":true,"visible":false},{"text":"Releases histamine","correct":false,"visible":false},{"text":"Has basophilic cytoplasm","correct":false,"visible":false},{"text":"Contains blue/purple staining granules","correct":false,"visible":false},{"text":"contains lobed nucleus","correct":false,"visible":false}]},{"id":3836,"text":"Which of the following is a precursor for plasma cells?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 102.","responses":[{"text":"B lymphocytes","correct":true,"visible":false},{"text":"Megakaryocytes","correct":false,"visible":false},{"text":"Platelets","correct":false,"visible":false},{"text":"Red blood cells","correct":false,"visible":false},{"text":"T lymphocytes","correct":false,"visible":false}]},{"id":3863,"text":"The specialized epithelium is present in which of the following lymphoid organ?","explanation":"The **thymus** is a primary lymphoid organ located in the upper chest, behind the sternum. It plays a crucial role in the development and maturation of T-lymphocytes, a type of white blood cell involved in cell-mediated immunity.\r\n\r\nThe thymus is characterized by a unique structure composed of two distinct regions: the cortex and the medulla. The cortex contains densely packed thymocytes, which are immature T-cells undergoing development and selection. Surrounding the thymocytes is a specialized epithelium known as the **thymic epithelium**, which provides a supportive environment for T-cell maturation.\r\n\r\nThe thymic epithelium consists of two main types of cells: cortical epithelial cells and medullary epithelial cells. These cells play a crucial role in promoting T-cell development, regulating the selection and maturation of T-cells, and preventing the development of self-reactive T-cells.","reference":"Alawam AS, Anderson G, Lucas B. Generation and regeneration of thymic epithelial cells. Frontiers in Immunology. Published May 7, 2020. Accessed May 29, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC7221188/","responses":[{"text":"Lymphoid tissue","correct":false,"visible":false},{"text":"Tonsils","correct":false,"visible":false},{"text":"Spleen","correct":false,"visible":false},{"text":"Lymph nodes","correct":false,"visible":false},{"text":"Thymus","correct":true,"visible":false}]},{"id":3865,"text":"Cytotoxic T cells destroy microbes in which part of the cell?","explanation":null,"reference":"Charles A Janeway J, Travers P, Walport M, Shlomchik MJ. T cell-mediated cytotoxicity. Immunobiology: The Immune System in Health and Disease. 5th edition. Published 2001. Accessed June 12, 2022. https://www.ncbi.nlm.nih.gov/books/NBK27101/","responses":[{"text":"Smooth endoplasmic reticulum","correct":false,"visible":false},{"text":"Rough endoplasmic reticulum","correct":false,"visible":false},{"text":"Golgi Apparatus","correct":false,"visible":false},{"text":"Cell membrane","correct":false,"visible":false},{"text":"Cytoplasm","correct":true,"visible":false}]},{"id":3976,"text":"Major cationic protein is present in the granules of which cell?","explanation":null,"reference":"Eosinophil cationic protein - an overview | sciencedirect topics. Accessed May 30, 2022. https://www.sciencedirect.com/topics/biochemistry-genetics-and-molecular-biology/eosinophil-cationic-protein","responses":[{"text":"Neutrophils","correct":false,"visible":false},{"text":"Basophils","correct":false,"visible":false},{"text":"Mast cells","correct":false,"visible":false},{"text":"Monocytes","correct":false,"visible":false},{"text":"Eosinophils","correct":true,"visible":false}]},{"id":3995,"text":"Which of the following substances is a plasminogen activator inhibitor?","explanation":null,"reference":"Katzung BG, Kruidering-Hall M, Trevor AJ. Katzung \u0026 Trevor’s Pharmacology Examination \u0026 Board Review. 12th ed. McGraw-Hill Education; 2019: 290.","responses":[{"text":"Vitamin K","correct":false,"visible":false},{"text":"Urokinase","correct":false,"visible":false},{"text":"Aminocaproic acid","correct":true,"visible":false},{"text":"Streptokinase","correct":false,"visible":false},{"text":"Fresh frozen plasma","correct":false,"visible":false}]},{"id":4138,"text":"Which type of antibodies are found in tears and saliva?","explanation":null,"reference":"Le T, Vikas Bhushan. First Aid for the USMLE Step 1 2021. 31st ed. McGraw-Hill Education; 2021: 105.","responses":[{"text":"IgA","correct":true,"visible":false},{"text":"IgG","correct":false,"visible":false},{"text":"IgD","correct":false,"visible":false},{"text":"IgM","correct":false,"visible":false},{"text":"IgE","correct":false,"visible":false}]},{"id":4139,"text":"Hemolytic anemia is the result of which hypersensitivity reaction?","explanation":null,"reference":"Justiz Vaillant AA, Vashisht R, Zito PM. Immediate hypersensitivity reactions. StatPearls. Published 2022. Accessed May 29, 2022. http://www.ncbi.nlm.nih.gov/books/NBK513315/","responses":[{"text":"Type 5","correct":false,"visible":false},{"text":"Type 2","correct":true,"visible":false},{"text":"Type 4","correct":false,"visible":false},{"text":"Type 3","correct":false,"visible":false},{"text":"Type 1","correct":false,"visible":false}]},{"id":4141,"text":"Which of the following is not an anticancer drug?","explanation":null,"reference":"Sun J, Wei Q, Zhou Y, Wang J, Liu Q, Xu H. A systematic analysis of FDA-approved anticancer drugs. BMC Systems Biology. Published October 3, 2017. Accessed June 14, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC5629554/","responses":[{"text":"Bleomycin","correct":false,"visible":false},{"text":"Etoposide","correct":false,"visible":false},{"text":"Dactinomycin","correct":false,"visible":false},{"text":"Streptomycin","correct":true,"visible":false},{"text":"Vinblastine","correct":false,"visible":false}]},{"id":4143,"text":"Hemopoiesis is production of which of the following?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 254","responses":[{"text":"Red blood cells","correct":false,"visible":false},{"text":"Platelets","correct":false,"visible":false},{"text":"Stem cells","correct":false,"visible":false},{"text":"White blood cells","correct":false,"visible":false},{"text":"All blood cells","correct":true,"visible":false}]},{"id":4144,"text":"Which anti-TB drug is given parenterally?","explanation":null,"reference":"Padda IS, Muralidhara Reddy K. Antitubercular medications. StatPearls. Published 2022. Accessed June 14, 2022. http://www.ncbi.nlm.nih.gov/books/NBK557666/","responses":[{"text":"Streptomycin","correct":true,"visible":false},{"text":"Isoniazid","correct":false,"visible":false},{"text":"Ethambutol","correct":false,"visible":false},{"text":"Rifampin","correct":false,"visible":false},{"text":"Pyrazinamide","correct":false,"visible":false}]},{"id":4145,"text":"Blood plasma level is maintained by which of the following?","explanation":null,"reference":"1) Hall JE. Guyton and Hall Textbook of Medical Physiology. 12th ed. Saunders/Elsevier; 2011: 833.\r\n  \r\n2) Mathew J, Sankar P, Varacallo M. Physiology, blood plasma. StatPearls. Published 2022. Accessed June 12, 2022. http://www.ncbi.nlm.nih.gov/books/NBK531504/","responses":[{"text":"Plasma proteins","correct":true,"visible":false},{"text":"Estrogen","correct":false,"visible":false},{"text":"Thyroxine","correct":false,"visible":false},{"text":"Testosterone","correct":false,"visible":false},{"text":"RBCs","correct":false,"visible":false}]},{"id":4196,"text":"Which of the following is involved in the inhibition of chemotaxis?","explanation":null,"reference":"Lee TH, Horton CE, Kyan-Aung U, Haskard D, Crea AE, Spur BW. Lipoxin A4 and lipoxin B4 inhibit chemotactic responses of human neutrophils stimulated by leukotriene B4 and N-formyl-L-methionyl-L-leucyl-L-phenylalanine. Clinical Science (London, England: 1979).","responses":[{"text":"C3a and C5a","correct":false,"visible":false},{"text":"Tumor necrosis factor(TNF) and Interleukin-1","correct":false,"visible":false},{"text":"Lipoxin","correct":true,"visible":false},{"text":"Prostaglandins","correct":false,"visible":false},{"text":"Chemokine","correct":false,"visible":false}]},{"id":4200,"text":"Leukotrienes are synthesized by which of the following?","explanation":null,"reference":"Lipoxygenase - an overview | sciencedirect topics. Accessed May 30, 2022. https://www.sciencedirect.com/topics/nursing-and-health-professions/lipoxygenase","responses":[{"text":"Cyclooxygenase-1 (COX-1)","correct":false,"visible":false},{"text":"Prostaglandins","correct":false,"visible":false},{"text":"Cyclooxygenase 2 (COX-2)","correct":false,"visible":false},{"text":"Lipoxygenase","correct":true,"visible":false},{"text":"Phospholipase A2","correct":false,"visible":false}]},{"id":4202,"text":"Which of the following is the incorrect statement regarding granulocytes?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 241.","responses":[{"text":"They contain non-specific azurophilic granules","correct":false,"visible":false},{"text":"They contain a single nucleus with multiple lobes","correct":false,"visible":false},{"text":"Granulocytes are also called myeloid cells","correct":false,"visible":false},{"text":"The term polymorph refers to eosinophils","correct":true,"visible":false},{"text":"They contain specific granules","correct":false,"visible":false}]},{"id":4205,"text":"Which of the following is the correct statement regarding the cell cycle?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 58.","responses":[{"text":"S phase is DNA replication phase","correct":true,"visible":false},{"text":"G2 is the same as the mitotic phase","correct":false,"visible":false},{"text":"I phase is the mitotic phase","correct":false,"visible":false},{"text":"S phase is synthesis of organelles","correct":false,"visible":false},{"text":"G1 is premitotic phase","correct":false,"visible":false}]},{"id":4209,"text":"Primary health care involves which of the following?","explanation":null,"reference":"White F. Primary health care and public health: foundations of universal health systems. Medical Principles and Practice. Published February 2015. Accessed May 30, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC5588212/","responses":[{"text":"Justice, equity, resources","correct":false,"visible":false},{"text":"Justice, fairness, ethics","correct":false,"visible":false},{"text":"Planning, effictivness, fairness","correct":false,"visible":false},{"text":"Resources, planning, situation analysis","correct":false,"visible":false},{"text":"Equity, effectiveness, efficiency","correct":true,"visible":false}]},{"id":4210,"text":"How many amino acids does alpha-hemoglobin have?","explanation":null,"reference":"Marengo-Rowe AJ. Structure-function relations of human hemoglobins. Proc (Bayl Univ Med Cent). 2006;19(3):239-245. Accessed May 30, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC1484532/","responses":[{"text":"141","correct":true,"visible":false},{"text":"118","correct":false,"visible":false},{"text":"115","correct":false,"visible":false},{"text":"184","correct":false,"visible":false},{"text":"162","correct":false,"visible":false}]},{"id":4213,"text":"What are the first identified cells of red blood cells (RBC) series?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018.: 259, 265.","responses":[{"text":"Thrombocyte","correct":false,"visible":false},{"text":"Proerythroblasts","correct":true,"visible":false},{"text":"Normoblasts","correct":false,"visible":false},{"text":"Polychromatic erythroblasts","correct":false,"visible":false},{"text":"Reticulocyte","correct":false,"visible":false}]},{"id":4215,"text":"Radicals are physiologically formed in which of the following?","explanation":null,"reference":"1) Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 150.\r\n\r\n2) Nüsse O. Biochemistry of the phagosome: the challenge to study a transient organelle. The Scientific World Journal. Published December 4, 2011. Accessed June 12, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC3236389/","responses":[{"text":"Nucleus","correct":false,"visible":false},{"text":"Phagolysosomes","correct":true,"visible":false},{"text":"Mitochondrion","correct":false,"visible":false},{"text":"Proteins","correct":false,"visible":false},{"text":"Cell membrane","correct":false,"visible":false}]},{"id":4216,"text":"Type-1 hypersensitivity involves which of the following?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Robbins SL, eds. Robbins Basic Pathology. 9th ed. Elsevier/Saunders; 2013: 200.","responses":[{"text":"Neutrophil","correct":false,"visible":false},{"text":"IgG","correct":false,"visible":false},{"text":"Basophil","correct":false,"visible":false},{"text":"IgA","correct":false,"visible":false},{"text":"Mast cell","correct":true,"visible":false}]},{"id":4217,"text":"Which test is not neccessary in initial diagnosis of hemoglobin deficiency?","explanation":null,"reference":"Freeman AM, Rai M, Morando DW. Anemia screening. In: StatPearls. StatPearls Publishing; 2022. Accessed June 14, 2022. http://www.ncbi.nlm.nih.gov/books/NBK499905/","responses":[{"text":"Blood smear","correct":false,"visible":false},{"text":"WBC count","correct":false,"visible":false},{"text":"Platelet count","correct":false,"visible":false},{"text":"Bone marrow","correct":true,"visible":false},{"text":"RBC indices","correct":false,"visible":false}]},{"id":4291,"text":"What is the daily requirement for Vitamin B12?","explanation":null,"reference":"Folate I of M (US) SC on the SE of DRI and its P on, Vitamins OB, Choline A. Vitamin b12. Published 1998. Accessed May 30, 2022. https://www.ncbi.nlm.nih.gov/books/NBK114302/","responses":[{"text":"2-3 μg","correct":true,"visible":false},{"text":"0.05-1 μg","correct":false,"visible":false},{"text":"30-35 μg","correct":false,"visible":false},{"text":"80-100 μg","correct":false,"visible":false},{"text":"10-15 μg","correct":false,"visible":false}]},{"id":4299,"text":"Which immunosuppressant is also a IL-2 inhibitor?","explanation":null,"reference":"Ferrini S, Moretta A, Biassoni R, Nicolin A, Moretta L. Cyclosporin-A inhibits IL-2 production by all human T-cell clones having this function, independent of the T4/T8 phenotype or the coexpression of cytolytic activity. Clinical Immunology and Immunopathology.","responses":[{"text":"Mofetil","correct":false,"visible":false},{"text":"Cyclosporine","correct":true,"visible":false},{"text":"Sirolimus","correct":false,"visible":false},{"text":"Daclizumab","correct":false,"visible":false},{"text":"Azathioprine","correct":false,"visible":false}]},{"id":4308,"text":"What does not cause the cobalamin deficiency?","explanation":null,"reference":"Ankar A, Kumar A. Vitamin b12 deficiency. StatPearls. Published 2022. Accessed June 12, 2022. http://www.ncbi.nlm.nih.gov/books/NBK441923/","responses":[{"text":"Inadequate diet","correct":false,"visible":false},{"text":"Tape worm infection","correct":false,"visible":false},{"text":"Esophagitis","correct":true,"visible":false},{"text":"Pernicious Anemia","correct":false,"visible":false},{"text":"Deficiency of intrinsic factor","correct":false,"visible":false}]},{"id":4327,"text":"Which of the following drug is not topical?","explanation":null,"reference":"Using medication: Topical medications. Published August 10, 2017. Accessed June 14, 2022. https://www.ncbi.nlm.nih.gov/books/NBK361003/","responses":[{"text":"None of these","correct":false,"visible":false},{"text":"Streptomycin","correct":true,"visible":false},{"text":"Nitroglycerin","correct":false,"visible":false},{"text":"Lidocaine","correct":false,"visible":false},{"text":"Estradiol","correct":false,"visible":false}]},{"id":4336,"text":"In which of the following conditions, round, microcytic, and hypochromic red blood cells are not usually seen in?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Robbins SL, eds. Robbins Basic Pathology. 9th ed. Elsevier/Saunders; 2013: 632.","responses":[{"text":"Sideroblastic anemia","correct":false,"visible":false},{"text":"Hereditary spherocytosis","correct":true,"visible":false},{"text":"Beta thalassemia major","correct":false,"visible":false},{"text":"Iron deficiency anemia","correct":false,"visible":false},{"text":"Beta thalassemia minor","correct":false,"visible":false}]},{"id":4337,"text":"Which of the following anti-cancer drug is not a cell cycle specific?","explanation":null,"reference":"Ogino MH, Tadi P. Cyclophosphamide. StatPearls. Published 2022. Accessed June 14, 2022. http://www.ncbi.nlm.nih.gov/books/NBK553087/","responses":[{"text":"Methotrexate","correct":false,"visible":false},{"text":"Bleomycin","correct":false,"visible":false},{"text":"Cyclophosphamide","correct":true,"visible":false},{"text":"Vinblastine","correct":false,"visible":false},{"text":"Vincristine","correct":false,"visible":false}]},{"id":4338,"text":"A 32-year-old female presented to OPD with bleeding gums, epistaxis, and non-palpable rashes. What is the most likely diagnosis?","explanation":null,"reference":null,"responses":[{"text":"Von Willebrand disease","correct":false,"visible":false},{"text":"Vitamin K deficiency","correct":false,"visible":false},{"text":"Hemophilia B","correct":false,"visible":false},{"text":"Platelet disorder","correct":true,"visible":false},{"text":"Hemophilia A","correct":false,"visible":false}]},{"id":4366,"text":"What does anemia in thalassemia lead to?","explanation":null,"reference":"Piga A. Impact of bone disease and pain in thalassemia. Hematology: the American Society of Hematology Education Program. Published December 8, 2017. Accessed May 30, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC6142535/","responses":[{"text":"Convulsions","correct":false,"visible":false},{"text":"Skeletal deformities","correct":true,"visible":false},{"text":"Protuberant abdomen","correct":false,"visible":false},{"text":"Stunted growth","correct":false,"visible":false},{"text":"Genetic mutations","correct":false,"visible":false}]},{"id":4367,"text":"Which of the following is the gold standard diagnostic test for thalassemia?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Robbins SL, eds. Robbins Basic Pathology. 9th ed. Elsevier/Saunders; 2013: 641.","responses":[{"text":"Complete blood count (CBC)","correct":false,"visible":false},{"text":"Hemoglobin electrophoresis","correct":true,"visible":false},{"text":"Polymerase chain reaction","correct":false,"visible":false},{"text":"Peripheral blood smear","correct":false,"visible":false},{"text":"Red cell distribution width (RDW)","correct":false,"visible":false}]},{"id":4368,"text":"Where does intrinsic factor release from?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Robbins SL, eds. Robbins Basic Pathology. 9th ed. Elsevier/Saunders; 2013: 206.","responses":[{"text":"Interstitial cells of Cajal","correct":false,"visible":false},{"text":"Pacemaker cells of the GI tract","correct":false,"visible":false},{"text":"Parietal Cells of the stomach","correct":true,"visible":false},{"text":"D1 cells of pancreas","correct":false,"visible":false},{"text":"Interstitial cells of Leydig","correct":false,"visible":false}]},{"id":4369,"text":"What is not a common pathway of metastasis?","explanation":null,"reference":"Khan I, Steeg PS. Metastasis suppressors: functional pathways. Laboratory investigation; a journal of technical methods and pathology. Published February 2018. Accessed May 30, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC6545599/","responses":[{"text":"Local invasion","correct":true,"visible":false},{"text":"Seeding to body cavity","correct":false,"visible":false},{"text":"Seeding to other body surfaces","correct":false,"visible":false},{"text":"Hematogenous spread","correct":false,"visible":false},{"text":"Lymphatic spread","correct":false,"visible":false}]},{"id":4370,"text":"Which of the agents are responsible for causing cancer?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 41.","responses":[{"text":"Adenoviruses","correct":false,"visible":false},{"text":"Blood transfusion","correct":false,"visible":false},{"text":"Mutagens","correct":false,"visible":false},{"text":"Nicotine","correct":false,"visible":false},{"text":"Carcinogens","correct":true,"visible":false}]},{"id":4371,"text":"What is pyrrole made up of?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 417.","responses":[{"text":"2 Succinyl COA","correct":false,"visible":false},{"text":"2 Succinyl CoA + 2 glycine","correct":true,"visible":false},{"text":"2 Glycine","correct":false,"visible":false},{"text":"2 Hb beta chains","correct":false,"visible":false},{"text":"2 Hb alpha chains","correct":false,"visible":false}]},{"id":4372,"text":"Which of the following statements regarding the role of retinoblastoma (Rb) gene during the cell cycle is correct?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Robbins SL, eds. Robbins Basic Pathology. 9th ed. Elsevier/Saunders; 2013: 26.","responses":[{"text":"It promotes the transition from G2 to M phase","correct":false,"visible":false},{"text":"It inhibits the transition from G2 to M phase","correct":false,"visible":false},{"text":"It promotes the transition from M to G₀ phase","correct":false,"visible":false},{"text":"It inhibits the transition from G1 to S phase","correct":true,"visible":false},{"text":"It promotes the transition from G1 to S phase","correct":false,"visible":false}]},{"id":4373,"text":"The parents of a child with iron-deficiency anemia are being counseled regarding dietary modifications. Which of the following food items should be added to the diet of this child?","explanation":null,"reference":"Beck KL, Conlon CA, Kruger R, Coad J. Dietary determinants of and possible solutions to iron deficiency for young women living in industrialized countries: a review. Nutrients. Published September 19, 2014. Accessed June 12, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC4179187/","responses":[{"text":"Rice","correct":false,"visible":false},{"text":"Tea","correct":false,"visible":false},{"text":"High-fiber diet","correct":false,"visible":false},{"text":"Citrus fruits","correct":true,"visible":false},{"text":"Legumes","correct":false,"visible":false}]},{"id":4375,"text":"Gastrectomy requires a lifelong administration of what?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Robbins SL, eds. Robbins Basic Pathology. 9th ed. Elsevier/Saunders; 2013: 648.","responses":[{"text":"Vitamin B-6","correct":false,"visible":false},{"text":"Vitamin A","correct":false,"visible":false},{"text":"Vitamin D","correct":false,"visible":false},{"text":"Vitamin B-12","correct":true,"visible":false},{"text":"Vitamin C","correct":false,"visible":false}]},{"id":4377,"text":"Which of the following is considered as negative reinforcement?","explanation":null,"reference":"Sidman M. The distinction between positive and negative reinforcement: some additional considerations. The Behavior Analyst. Published 2006. Accessed June 12, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC2223177/","responses":[{"text":"Punishment will prevent the repetition of behavior","correct":false,"visible":false},{"text":"Punishment will encourage the repetition of positive behavior","correct":false,"visible":false},{"text":"Removal of reward prevent the repetition of behavior","correct":false,"visible":false},{"text":"Removal of painful situation will encourage the repetition of behavior","correct":true,"visible":false},{"text":"Reward will prevent the repetition of negative behavior","correct":false,"visible":false}]},{"id":4378,"text":"What is another name for operant conditioning?","explanation":null,"reference":"Staddon JER, Cerutti DT. Operant conditioning. Annual review of psychology. Published 2003. Accessed June 12, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC1473025/","responses":[{"text":"Instrumental conditioning","correct":true,"visible":false},{"text":"Classical conditioning","correct":false,"visible":false},{"text":"Pavlovian Conditioning","correct":false,"visible":false},{"text":"Observational learning","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":4380,"text":"Which of the following is not responsible for the tensile strength of a wound during healing?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 110.","responses":[{"text":"Collagen cross linking","correct":false,"visible":false},{"text":"Structural collagen modifications","correct":false,"visible":false},{"text":"Increase in the size of collagen fibers","correct":false,"visible":false},{"text":"Collagen fibrosis","correct":true,"visible":false},{"text":"Collagen synthesis","correct":false,"visible":false}]},{"id":4382,"text":"What does a deficiency of C1 esterase inhibitor lead to?","explanation":null,"reference":"Kerrigan MJ, Naik P. C1 Esterase Inhibitor Deficiency. [Updated 2021 Jul 13]. In: StatPearls [Internet]. Treasure Island (FL): StatPearls Publishing; 2022 Jan-. Available from: https://www.ncbi.nlm.nih.gov/books/NBK538166/","responses":[{"text":"Episodes of edema that never resolve","correct":true,"visible":false},{"text":"Urticaria is a presenting feature","correct":false,"visible":false},{"text":"Decrease immunity","correct":false,"visible":false},{"text":"Delay in immune response","correct":false,"visible":false},{"text":"Increase in anaphylatoxins","correct":false,"visible":false}]},{"id":4383,"text":"What is the correct function of Fab fragment of antibodies?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 13th ed. McGraw-Hill Medical; 2013: 270.","responses":[{"text":"Antigen binding","correct":true,"visible":false},{"text":"Binding to specific proteins","correct":false,"visible":false},{"text":"All of these are functions of Fab","correct":false,"visible":false},{"text":"Binding to cells receptors","correct":false,"visible":false},{"text":"Binding to complement proteins","correct":false,"visible":false}]},{"id":4392,"text":"Which of the following is not a part of the vascular events of acute inflammation?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Robbins SL, eds. Robbins Basic Pathology. 9th ed. Elsevier/Saunders; 2013: 73.","responses":[{"text":"Stasis","correct":false,"visible":false},{"text":"Increased vascular permeability","correct":false,"visible":false},{"text":"Diapedesis","correct":false,"visible":false},{"text":"Attraction of leukocytes to the site of injury","correct":false,"visible":false},{"text":"Migration of endothelial cells","correct":true,"visible":false}]},{"id":4394,"text":"Which of the following is prolonged by the administration of low-dose heparin?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 277.","responses":[{"text":"Activated partial thromboplastin time (aPTT)","correct":true,"visible":false},{"text":"Clotting time","correct":false,"visible":false},{"text":"Bleeding time","correct":false,"visible":false},{"text":"Prothrombin time (PT)","correct":false,"visible":false},{"text":"Bleeding time and prothrombin time (PT)","correct":false,"visible":false}]},{"id":4395,"text":"Which one of the following enzymes is dependent on vitamin K to help in the formation of coagulation factors?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 484.","responses":[{"text":"Dehydrogenase","correct":false,"visible":false},{"text":"Carboxylase","correct":true,"visible":false},{"text":"Oxidase","correct":false,"visible":false},{"text":"Transferase","correct":false,"visible":false},{"text":"Decarboxylase","correct":false,"visible":false}]},{"id":4396,"text":"How does cimetidine inhibit warfarin?","explanation":null,"reference":"Hussey EK, Dukes GE. Do all histamine2-antagonists cause a warfarin drug interaction? DICP: the annals of pharmacotherapy.","responses":[{"text":"By decreasing warfarin metabolism","correct":false,"visible":false},{"text":"Increasing warfarin metabolism/breakdown","correct":true,"visible":false},{"text":"By increasing anticoagulants","correct":false,"visible":false},{"text":"By enhancing erythropoiesis","correct":false,"visible":false},{"text":"By decreasing antithrombin III formation","correct":false,"visible":false}]},{"id":4397,"text":"All the cells of blood originate from which of the following?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 13th ed. McGraw-Hill Medical; 2013: 254.","responses":[{"text":"Colony forming unit","correct":false,"visible":false},{"text":"Committed stem cells","correct":false,"visible":false},{"text":"Growth and differentiation inducer cells","correct":false,"visible":false},{"text":"Megakaryocytes","correct":false,"visible":false},{"text":"Pluripotent hematopoietic stem cells","correct":true,"visible":false}]},{"id":4398,"text":"What is the average sum of squares of the deviation about mean, divided by N is called?","explanation":null,"reference":"Wadhwa RR, Azzam D. Variance. StatPearls. Published 2022. Accessed June 14, 2022. http://www.ncbi.nlm.nih.gov/books/NBK551689/","responses":[{"text":"Mean deviation","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Variance","correct":true,"visible":false},{"text":"Absolute deviation","correct":false,"visible":false},{"text":"Standard deviation","correct":false,"visible":false}]},{"id":4399,"text":"Which drug is bacteriostatic but becomes bactericidal if given in high doses?","explanation":null,"reference":"1) PubChem. Chloramphenicol. Accessed June 14, 2022. https://pubchem.ncbi.nlm.nih.gov/compound/5959\r\n\r\n2) Loree J, Lappin SL. Bacteriostatic antibiotics. StatPearls. Published 2022. Accessed June 14, 2022. http://www.ncbi.nlm.nih.gov/books/NBK547678/","responses":[{"text":"Capreomycin","correct":false,"visible":false},{"text":"Isoniazid","correct":false,"visible":false},{"text":"Chloramphenicol","correct":true,"visible":false},{"text":"Pyrazinamide","correct":false,"visible":false},{"text":"Rifampicin","correct":false,"visible":false}]},{"id":4400,"text":"Which malarial parasite causes severe malaria?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Robbins SL, eds. Robbins Basic Pathology. 9th ed. Elsevier/Saunders; 2013: 390-391.","responses":[{"text":"Plasmodium malariae","correct":false,"visible":false},{"text":"Plasmodium falciparum","correct":true,"visible":false},{"text":"Plasmodium vivax","correct":false,"visible":false},{"text":"Plasmodium ovale","correct":false,"visible":false},{"text":"Plasmodium knowlesi","correct":false,"visible":false}]},{"id":4401,"text":"Regarding DiGeorge syndrome, select the inappropriate one:","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Robbins SL, eds. Robbins Basic Pathology. 9th ed. Elsevier/Saunders; 2013: 241.","responses":[{"text":"Defect in 3rd \u0026 4th pharyngeal pouch","correct":false,"visible":false},{"text":"B cell immunodeficiency syndrome","correct":true,"visible":false},{"text":"Tetany","correct":false,"visible":false},{"text":"T cell immunodeficiency syndrome","correct":false,"visible":false},{"text":"Heart and blood vessel enlargement","correct":false,"visible":false}]},{"id":4402,"text":"What is the normal bleeding time in the Duke method?","explanation":null,"reference":null,"responses":[{"text":"10-15 minutes","correct":false,"visible":false},{"text":"15-30 seconds","correct":false,"visible":false},{"text":"1-6 minutes","correct":true,"visible":false},{"text":"5-10 minutes","correct":false,"visible":false},{"text":"2-8 minute","correct":false,"visible":false}]},{"id":4403,"text":"Interferon gamma activates which of the following?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Robbins SL, eds. Robbins Basic Pathology. 9th ed. Elsevier/Saunders; 2013: 80, 94.","responses":[{"text":"T cells","correct":false,"visible":false},{"text":"B cells","correct":false,"visible":false},{"text":"Macrophages","correct":true,"visible":false},{"text":"Mast cells","correct":false,"visible":false},{"text":"Basophils","correct":false,"visible":false}]},{"id":4405,"text":"Lymphoid organ with outer darkly staining and inner lightly staining with patches of acidophilic type?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 13th ed. McGraw-Hill Medical; 2013: 276.","responses":[{"text":"Bone marrow","correct":false,"visible":false},{"text":"Spleen","correct":false,"visible":false},{"text":"Liver","correct":false,"visible":false},{"text":"Thymus","correct":true,"visible":false},{"text":"Lymph node","correct":false,"visible":false}]},{"id":4406,"text":"The thymus is derived from which of the following?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 13th ed. McGraw-Hill Medical; 2013: 276.","responses":[{"text":"4th pharyngeal pouch","correct":false,"visible":false},{"text":"1st pharyngeal pouch","correct":false,"visible":false},{"text":"3rd pharyngeal pouch","correct":true,"visible":false},{"text":"2nd pharyngeal arch","correct":false,"visible":false},{"text":"5th pharengeal arch","correct":false,"visible":false}]},{"id":4408,"text":"A person contains both type A and B antibodies. What would his blood group be?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 445.","responses":[{"text":"A-","correct":false,"visible":false},{"text":"AB+","correct":false,"visible":false},{"text":"D","correct":false,"visible":false},{"text":"O-","correct":true,"visible":false},{"text":"B+","correct":false,"visible":false}]},{"id":4409,"text":"Which of the following vitamins do the clotting factors II, VII, IX, and X depend on for their synthesis?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 484.","responses":[{"text":"Vitamin E","correct":false,"visible":false},{"text":"Vitamin K","correct":true,"visible":false},{"text":"Vitamin B","correct":false,"visible":false},{"text":"Vitamin D","correct":false,"visible":false},{"text":"Vitamin A","correct":false,"visible":false}]},{"id":4410,"text":"What is the volume of the formed elements in blood?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 13th ed. McGraw-Hill Medical; 2013: 237.","responses":[{"text":"55%","correct":false,"visible":false},{"text":"28%","correct":false,"visible":false},{"text":"35%","correct":false,"visible":false},{"text":"45%","correct":true,"visible":false},{"text":"33%","correct":false,"visible":false}]},{"id":4411,"text":"Which of the following is a major source of vitamin K?","explanation":null,"reference":"Suttie JW, Booth SL. Vitamin k1. Advances in Nutrition. Published September 6, 2011. Accessed June 12, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC3183594/","responses":[{"text":"Green leafy vegetables","correct":true,"visible":false},{"text":"Mother's milk","correct":false,"visible":false},{"text":"Meat","correct":false,"visible":false},{"text":"Date","correct":false,"visible":false},{"text":"Fish","correct":false,"visible":false}]},{"id":4412,"text":"Which of the following is not related to inflammation?","explanation":null,"reference":null,"responses":[{"text":"COX-1","correct":false,"visible":false},{"text":"Lipoxin","correct":false,"visible":false},{"text":"COX-2","correct":false,"visible":false},{"text":"Thromboxane","correct":true,"visible":false},{"text":"Prostacyclin","correct":false,"visible":false}]},{"id":4414,"text":"Which of the following is the best test for the diagnosis of malaria?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Robbins SL, eds. Robbins Basic Pathology. 9th ed. Elsevier/Saunders; 2013: 391.","responses":[{"text":"Microbiological culture","correct":false,"visible":false},{"text":"Enzyme-linked immunoassay (ELISA) test","correct":false,"visible":false},{"text":"Thick and thin film","correct":true,"visible":false},{"text":"Serologic test","correct":false,"visible":false},{"text":"Pap smear","correct":false,"visible":false}]},{"id":4416,"text":"What is the major function of complement protein C1?","explanation":null,"reference":"Sarma JV, Ward PA. The complement system. Cell and Tissue Research. Published 2011. Accessed June 12, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC3097465/","responses":[{"text":"Agglutination","correct":false,"visible":false},{"text":"Binding to Fc IgG and IgM","correct":true,"visible":false},{"text":"Opsonisation","correct":false,"visible":false},{"text":"Neutrophil chemotactic agent","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":4417,"text":"Which of the following induces contraction of endothelial cells to increase vascular permeability?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 280.","responses":[{"text":"Prostaglandins","correct":false,"visible":false},{"text":"Fibrin","correct":false,"visible":false},{"text":"Histamine","correct":true,"visible":false},{"text":"Vascular endothelial growth factor","correct":false,"visible":false},{"text":"Serotonin","correct":false,"visible":false}]},{"id":4419,"text":"Which of the following is wrong regarding Wiskott Aldrich syndrome?","explanation":null,"reference":"Malik MA, Masab M. Wiskott-aldrich syndrome. StatPearls. Published 2022. Accessed June 12, 2022. http://www.ncbi.nlm.nih.gov/books/NBK539838/","responses":[{"text":"It is X-linked dominant","correct":true,"visible":false},{"text":"Associated with WASP gene","correct":false,"visible":false},{"text":"Causes patches across skin","correct":false,"visible":false},{"text":"It is an immune deficiency","correct":false,"visible":false},{"text":"Associated with T-cell defects","correct":false,"visible":false}]},{"id":4421,"text":"Which one of the following is not among the main cells that are involved in chronic inflammation?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Robbins SL, eds. Robbins Basic Pathology. 9th ed. Elsevier/Saunders; 2013: 94-97.","responses":[{"text":"Neutrophils","correct":true,"visible":false},{"text":"Macrophages","correct":false,"visible":false},{"text":"Lymphocytes","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Plasma cells","correct":false,"visible":false}]},{"id":4426,"text":"Which diagnostic test is done for megaloblastic anemia?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Robbins SL, eds. Robbins Basic Pathology. 9th ed. Elsevier/Saunders; 2013: 645.","responses":[{"text":"Complete blood count","correct":false,"visible":false},{"text":"Prothrombin time","correct":false,"visible":false},{"text":"Homocysteine levels","correct":false,"visible":false},{"text":"Serum folic acid and B12","correct":true,"visible":false},{"text":"Methylmalonic acid levels","correct":false,"visible":false}]},{"id":4435,"text":"High amounts of which of these make up the cell walls of the gram-positive bacteria?","explanation":null,"reference":"Salton MRJ, Kim KS, Baron S. Structure. Medical Microbiology. Published 1996. Accessed June 13, 2022. http://www.ncbi.nlm.nih.gov/books/NBK8477/","responses":[{"text":"Proteins","correct":false,"visible":false},{"text":"Peptidoglycans","correct":true,"visible":false},{"text":"Glycerol phosphate","correct":false,"visible":false},{"text":"Lipopolysaccharide","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":4436,"text":"What is passive transport?","explanation":null,"reference":"Cooper GM. Transport of small molecules. The Cell: A Molecular Approach. 2nd edition. Published 2000. Accessed June 12, 2022. https://www.ncbi.nlm.nih.gov/books/NBK9847/","responses":[{"text":"From low to high gradient","correct":false,"visible":false},{"text":"From high to low gradient using ATP","correct":false,"visible":false},{"text":"From low to high using ATP","correct":false,"visible":false},{"text":"From low to high across a membrane","correct":false,"visible":false},{"text":"From high to low gradient","correct":true,"visible":false}]},{"id":4439,"text":"A woman took aspirin while being pregnant. What would its effect be?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 11th ed. Saunders/Elsevier; 2020: 455.","responses":[{"text":"Gastric ulcer","correct":false,"visible":false},{"text":"Closure of ductus arteriosus","correct":true,"visible":false},{"text":"Post partum hemorrhage","correct":false,"visible":false},{"text":"Congenital Anomalies","correct":false,"visible":false},{"text":"No effect","correct":false,"visible":false}]},{"id":4441,"text":"What is major histocompatibility complex (MHC) genes present on?","explanation":null,"reference":"Cruz-Tapias P, Castiblanco J, Anaya JM. Major histocompatibility complex: Antigen processing and presentation. Published July 18, 2013. Accessed June 12, 2022. https://www.ncbi.nlm.nih.gov/books/NBK459467/","responses":[{"text":"Short arm of chromosome number 8","correct":false,"visible":false},{"text":"Short arm of chromosome number 13","correct":false,"visible":false},{"text":"Short arm of chromosome number 6","correct":true,"visible":false},{"text":"Long arm of chromosome number 21","correct":false,"visible":false},{"text":"Long arm of chromosome number 4","correct":false,"visible":false}]},{"id":4442,"text":"What is the most major histocompatibility complex (MHC) class for transplant determination?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 273.","responses":[{"text":"None of these","correct":false,"visible":false},{"text":"MHC class II","correct":false,"visible":false},{"text":"MHC class I","correct":true,"visible":false},{"text":"MHC class III","correct":false,"visible":false},{"text":"All of these","correct":false,"visible":false}]},{"id":4443,"text":"Which coagulation factor is deficient in hemophilia A?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Robbins SL, eds. Robbins Basic Pathology. 9th ed. Elsevier/Saunders; 2013: 143.","responses":[{"text":"XI","correct":false,"visible":false},{"text":"VIII","correct":true,"visible":false},{"text":"IX","correct":false,"visible":false},{"text":"II","correct":false,"visible":false},{"text":"V","correct":false,"visible":false}]},{"id":4447,"text":"Which of the following are Major histocompatibility complex (MHC) Class II alleles?","explanation":null,"reference":"van Lith M, McEwen-Smith RM, Benham AM. Hla-dp, hla-dq, and hla-dr have different requirements for invariant chain and hla-dm. The Journal of Biological Chemistry. Published December 24, 2010. Accessed June 13, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC3003381/","responses":[{"text":"HLA-DR, HLA-DQ, HL-C","correct":false,"visible":false},{"text":"HLA-A, HLA-B, HL-C","correct":false,"visible":false},{"text":"HLA-DR, HLA-DQ, HL-DP","correct":true,"visible":false},{"text":"HLA-A, HLB-DQ, HL-DP","correct":false,"visible":false},{"text":"C2, C4, TNF","correct":false,"visible":false}]},{"id":4450,"text":"What do Major histocompatibility complex (MHC) class III loci consists of?","explanation":null,"reference":"Charles A Janeway J, Travers P, Walport M, Shlomchik MJ. The major histocompatibility complex and its functions. Immunobiology: The Immune System in Health and Disease. 5th edition. Published 2001. Accessed June 13, 2022. https://www.ncbi.nlm.nih.gov/books/NBK27156/","responses":[{"text":"HLA-A, HLA-B, HLA-C","correct":false,"visible":false},{"text":"C2, C4, TNF, LT","correct":true,"visible":false},{"text":"HLA-DP, HLA-DQ, HLA-DR","correct":false,"visible":false},{"text":"HLA-DP, HLA-B, HLA-DR","correct":false,"visible":false},{"text":"C5a, C3a, C4","correct":false,"visible":false}]},{"id":4451,"text":"Which of the following are the signs of contact dermatitis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Robbins SL, eds. Robbins Basic Pathology. 9th ed. Elsevier/Saunders; 2013: 1164.","responses":[{"text":"Skin ulcers","correct":false,"visible":false},{"text":"Uremia","correct":false,"visible":false},{"text":"Inflammation with blisters","correct":true,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Fever","correct":false,"visible":false}]},{"id":4452,"text":"What is prenatal age?","explanation":null,"reference":null,"responses":[{"text":"From 6 months after conception to birth","correct":false,"visible":false},{"text":"From 3 months after conception to birth","correct":false,"visible":false},{"text":"From conception to birth","correct":true,"visible":false},{"text":"After birth","correct":false,"visible":false},{"text":"From birth till 1 year after","correct":false,"visible":false}]},{"id":4454,"text":"Which of the following is correct regarding erythrocytes?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 413.","responses":[{"text":"They consume the oxygen they carry","correct":false,"visible":false},{"text":"They are hemoglobin containing pigments","correct":false,"visible":false},{"text":"They form ATP anaerobically","correct":true,"visible":false},{"text":"Are nucleated cells","correct":false,"visible":false},{"text":"Become macrocytes in infection","correct":false,"visible":false}]},{"id":4455,"text":"Obstructive jaundice leads to the deficiency of:","explanation":null,"reference":"Clarke D, Pillay Y, Anderson F, Thomson S. The current standard of care in the periprocedural management of the patient with obstructive jaundice. Annals of The Royal College of Surgeons of England. Published November 2006. Accessed June 13, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC1963825/","responses":[{"text":"Ca+2 ions","correct":false,"visible":false},{"text":"Vitamin B12","correct":false,"visible":false},{"text":"Vitamin K","correct":true,"visible":false},{"text":"Vitamin C","correct":false,"visible":false},{"text":"Vitamin B9","correct":false,"visible":false}]},{"id":4456,"text":"Lymphadenopathy is most commonly seen in which of the following regions?","explanation":null,"reference":null,"responses":[{"text":"Neck","correct":true,"visible":false},{"text":"Arms","correct":false,"visible":false},{"text":"Head","correct":false,"visible":false},{"text":"Abdomen","correct":false,"visible":false},{"text":"Chest","correct":false,"visible":false}]},{"id":4459,"text":"What defects are found in hereditary spherocytosis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Robbins SL, eds. Robbins Basic Pathology. 9th ed. Elsevier/Saunders; 2013: 632.","responses":[{"text":"Improperly formed or weak spectrin, band 3, 4.2, and ankyrin proteins","correct":true,"visible":false},{"text":"Hyperchromic and microcytic red blood cells","correct":false,"visible":false},{"text":"Hypochromic and microcytic red blood cells","correct":false,"visible":false},{"text":"Hyperchromic red blood cells and weak spectrin","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":4462,"text":"What are ferritin and hemosiderin classified as?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 419.","responses":[{"text":"Iron binding proteins","correct":false,"visible":false},{"text":"Plasma iron","correct":false,"visible":false},{"text":"Transport form of iron","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Stored form of iron","correct":true,"visible":false}]},{"id":4467,"text":"Which of the following is an example of a type IV hypersensitivity reaction?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Robbins SL, eds. Robbins Basic Pathology. 9th ed. Elsevier/Saunders; 2013: 201.","responses":[{"text":"Systemic lupus erythematosus (SLE)","correct":false,"visible":false},{"text":"Arthus reaction","correct":false,"visible":false},{"text":"Graves disease","correct":false,"visible":false},{"text":"Contact dermatitis","correct":true,"visible":false},{"text":"Serum sickness","correct":false,"visible":false}]},{"id":4471,"text":"Which is incorrect about type III hypersensitivity?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Robbins SL, eds. Robbins Basic Pathology. 9th ed. Elsevier/Saunders; 2013: 207.","responses":[{"text":"Involve antigen-antibody reactions","correct":false,"visible":false},{"text":"Immune complexes formed are in circulation","correct":false,"visible":false},{"text":"They are also formed in extravascular tissues","correct":false,"visible":false},{"text":"Immune complexes are formed only in circulation","correct":true,"visible":false},{"text":"This type of reaction occurs in SLE","correct":false,"visible":false}]},{"id":4473,"text":"A secondary case is infected by which of the following?","explanation":null,"reference":"El-Gilany AH. COVID-19 caseness: An epidemiologic perspective. Journal of Infection and Public Health. Published January 2021. Accessed June 13, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC7832429/","responses":[{"text":"Quaternary case","correct":false,"visible":false},{"text":"Primary case","correct":true,"visible":false},{"text":"Another secondary case","correct":false,"visible":false},{"text":"Tertiary case","correct":false,"visible":false},{"text":"None of the options are correct","correct":false,"visible":false}]},{"id":4475,"text":"How would 'index case' be defined?","explanation":null,"reference":"El-Gilany AH. COVID-19 caseness: An epidemiologic perspective. Journal of Infection and Public Health. Published January 2021. Accessed June 7, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC7832429/","responses":[{"text":"An average case","correct":false,"visible":false},{"text":"Most symptomatic case","correct":false,"visible":false},{"text":"Least symptomatic case","correct":false,"visible":false},{"text":"First identified case","correct":true,"visible":false},{"text":"Most lethal case","correct":false,"visible":false}]},{"id":4477,"text":"Which of the following is incorrect regarding secondary immunodeficiencies?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Robbins SL, eds. Robbins Basic Pathology. 9th ed. Elsevier/Saunders; 2013: 243.","responses":[{"text":"Most common form is AIDS","correct":false,"visible":false},{"text":"Occur later in life","correct":false,"visible":false},{"text":"Result from infections, malnutrition, or treatment","correct":false,"visible":false},{"text":"Can cause an increased incidence of certain cancers","correct":false,"visible":false},{"text":"They are genetically determined","correct":true,"visible":false}]},{"id":4479,"text":"Which of the following agents directly activates plasminogen?","explanation":"**Urokinase** is the agent that **directly activates plasminogen**. Urokinase is a naturally occurring enzyme that is involved in the breakdown of blood clots. It directly converts plasminogen into plasmin, which then breaks down fibrin in the clot. Urokinase has been used therapeutically as a thrombolytic agent to dissolve blood clots in conditions such as deep vein thrombosis and pulmonary embolism.","reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017.","responses":[{"text":"Streptokinase","correct":false,"visible":false},{"text":"Urokinase","correct":true,"visible":false},{"text":"Tissue plasminogen activator (tPA)","correct":false,"visible":false},{"text":"Heparin","correct":false,"visible":false},{"text":"Warfarin","correct":false,"visible":false}]},{"id":4483,"text":"Which of the following are involved in type-2 hypersensitivity reactions?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 200.","responses":[{"text":"Antigen-antibody complexes","correct":false,"visible":false},{"text":"CD4 cells","correct":false,"visible":false},{"text":"IgE immunoglobulins","correct":false,"visible":false},{"text":"CD8 cells","correct":false,"visible":false},{"text":"IgG immunoglobulins","correct":true,"visible":false}]},{"id":4484,"text":"What are the antibodies involved in immediate hypersensitivity?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Robbins SL, eds. Robbins Basic Pathology. 9th ed. Elsevier/Saunders; 2013: 201.","responses":[{"text":"IgE","correct":true,"visible":false},{"text":"IgD","correct":false,"visible":false},{"text":"IgM","correct":false,"visible":false},{"text":"IgA","correct":false,"visible":false},{"text":"IgG","correct":false,"visible":false}]},{"id":4487,"text":"Which drug inhibits the ADP pathway of the platelet aggregation?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 273.","responses":[{"text":"Clopidogrel","correct":true,"visible":false},{"text":"Aspirin","correct":false,"visible":false},{"text":"Abciximab","correct":false,"visible":false},{"text":"Tirofiban","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":4490,"text":"Protein C and S are involved in which of the following?","explanation":"**Protein C and S** are involved in the **cleavage of clotting factors**. They are part of the anticoagulant system and function to regulate and inhibit the clotting process. Protein C acts as a natural anticoagulant by inactivating factors Va and VIIIa, which are involved in the clotting cascade. Protein S serves as a cofactor for protein C in its anticoagulant activity. Together, protein C and S help to maintain the balance between clotting and anticoagulation, preventing excessive clot formation.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 483.","responses":[{"text":"Enhancing chemotaxis","correct":false,"visible":false},{"text":"Decreasing bleeding time","correct":false,"visible":false},{"text":"Clotting","correct":false,"visible":false},{"text":"Cleavage of clotting factors","correct":true,"visible":false},{"text":"Fibrinolysis","correct":false,"visible":false}]},{"id":4491,"text":"Which of the following is an example of gamma globulins in circulation?","explanation":null,"reference":"1) Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 437\r\n\r\n2) Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 239.","responses":[{"text":"Immunoglobulin","correct":true,"visible":false},{"text":"Agglutinogen","correct":false,"visible":false},{"text":"Alpha-fetoprotein (AFP)","correct":false,"visible":false},{"text":"Transferrin","correct":false,"visible":false},{"text":"Albumin","correct":false,"visible":false}]},{"id":4493,"text":"Von Willibrand factor (VWF) is responsible for which of the following?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 452.","responses":[{"text":"Production of collagen","correct":false,"visible":false},{"text":"Production of cytokines","correct":false,"visible":false},{"text":"Attachment of platelets to endothelial wall","correct":true,"visible":false},{"text":"Repair of endothelium","correct":false,"visible":false},{"text":"Attachment of platelets to each other","correct":false,"visible":false}]},{"id":4495,"text":"Which of the following is true regarding Bruton's disease?","explanation":null,"reference":"Taneja A, Muco E, Chhabra A. Bruton agammaglobulinemia. StatPearls. Published 2022. Accessed June 13, 2022. http://www.ncbi.nlm.nih.gov/books/NBK448170/","responses":[{"text":"Is charectarized by defect in phagolysosome synthesis","correct":false,"visible":false},{"text":"B cells are not affected","correct":false,"visible":false},{"text":"Is autosomal dominent","correct":false,"visible":false},{"text":"B cells undergo maturation","correct":false,"visible":false},{"text":"T cells are not affected","correct":true,"visible":false}]},{"id":4497,"text":"Which of the following cells' development is impaired in severe combined immunodeficiency (SCID)?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Robbins SL, eds. Robbins Basic Pathology. 9th ed. Elsevier/Saunders; 2013: 240, 243.","responses":[{"text":"NK cells, B cells and T cells","correct":false,"visible":false},{"text":"NK cells and B cells","correct":false,"visible":false},{"text":"T cells only","correct":false,"visible":false},{"text":"T cells and B cells","correct":true,"visible":false},{"text":"NK cells only","correct":false,"visible":false}]},{"id":4499,"text":"Pick the incorrect statement regarding leukocytes:","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 423.","responses":[{"text":"They have one multilobed nucleus","correct":false,"visible":false},{"text":"They are nonspecific phagocytes","correct":false,"visible":false},{"text":"Macrophages and neutrophils are important phagocytes","correct":false,"visible":false},{"text":"Leukocytes are functionally active in circulation","correct":true,"visible":false},{"text":"Some contain specific granules","correct":false,"visible":false}]},{"id":4500,"text":"Pick the incorrect statement about leukocytes:","explanation":null,"reference":"Young B, O’Dowd G, Woodford P. Wheater’s Functional Histology: A Text and Colour Atlas. 6th ed. Churchill Livingston/Elsevier; 2014: 46.","responses":[{"text":"Neutrophils are polymorph","correct":false,"visible":false},{"text":"Granulocytes can be differentiated by stain","correct":false,"visible":false},{"text":"Eosinophils are anti-parasitic","correct":false,"visible":false},{"text":"Granulocytes originate from myeloid lineage","correct":false,"visible":false},{"text":"Neutrophil specific granules have affinity for methylene blue","correct":true,"visible":false}]},{"id":4501,"text":"Which of the following is correct about red blood cells (RBCs)?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 413.","responses":[{"text":"They contain all usual cellular organelles","correct":false,"visible":false},{"text":"They contain carbonic anhydrase","correct":true,"visible":false},{"text":"Their first stage of development is the reticulocyte","correct":false,"visible":false},{"text":"They are nucleated","correct":false,"visible":false},{"text":"They generate energy primarily via lipolysis","correct":false,"visible":false}]},{"id":8748,"text":"Erythropoietin is primarily formed in which organ?","explanation":"**Erythropoietin (EPO)** is primarily formed in the **kidneys**, specifically in the interstitial cells located in the peritubular capillaries of the renal cortex and outer medulla. A small amount of EPO is also produced in the liver.\r\n\r\nEPO is a glycoprotein hormone that plays a crucial role in regulating red blood cell production. It stimulates the production of red blood cells from hematopoietic stem cells in the bone marrow. EPO is released in response to decreased oxygen levels in the blood, detected by specialized cells in the kidneys called peritubular fibroblasts. Hypoxia-inducible factor (HIF) is activated in these cells, leading to the synthesis and secretion of EPO.\r\n\r\nThe production of EPO by the kidneys is tightly regulated to maintain the appropriate oxygen-carrying capacity of the blood. Conditions such as hypoxia, anemia, and renal disease can influence EPO production and lead to alterations in red blood cell production.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 414.","responses":[{"text":"Bone marrow","correct":false,"visible":false},{"text":"Kidneys","correct":true,"visible":false},{"text":"Liver","correct":false,"visible":false},{"text":"Brain","correct":false,"visible":false},{"text":"Spleen","correct":false,"visible":false}]},{"id":10143,"text":"Which antibody is found in the respiratory and digestive lining, as well as the saliva, tears, and breast milk?","explanation":null,"reference":"Le T, Vikas Bhushan. First Aid for the USMLE Step 1 2021. 31st ed. McGraw-Hill Education; 2021: 105.","responses":[{"text":"IgD","correct":false,"visible":false},{"text":"IgE","correct":false,"visible":false},{"text":"IgG","correct":false,"visible":false},{"text":"IgM","correct":false,"visible":false},{"text":"IgA","correct":true,"visible":false}]},{"id":11728,"text":"Palatine tonsil is derived from which of the following?","explanation":"The **palatine tonsil** is derived from the **2nd pharyngeal pouch** during embryonic development.\r\n\r\nDuring early development, the pharyngeal arches and pouches contribute to the formation of various structures in the head and neck region. The 2nd pharyngeal pouch gives rise to several important structures, including the palatine tonsils.\r\n\r\nThe palatine tonsils are a pair of lymphoid organs located on the lateral walls of the oropharynx. They play a role in the immune response by filtering and trapping pathogens that enter the body through the oral cavity.","reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 161.","responses":[{"text":"3rd pharyngeal arch","correct":false,"visible":false},{"text":"3rd pharyngeal pouch","correct":false,"visible":false},{"text":"2nd pharyngeal arch","correct":false,"visible":false},{"text":"2nd pharyngeal pouch","correct":true,"visible":false},{"text":"1st pharyngeal pouch","correct":false,"visible":false}]}
]

export default a